import React, { useEffect, useState } from 'react';

export default function PrescriptionsTab() {
  const [prescriptions, setPrescriptions] = useState([]);
  const [doctorName, setDoctorName] = useState('');
  const [medications, setMedications] = useState('');
  const [notes, setNotes] = useState('');
  const token = localStorage.getItem('token');

  useEffect(() => { fetchList(); }, []);

  async function fetchList() {
    const res = await fetch('http://localhost:5000/api/prescriptions', { headers: { Authorization: `Bearer ${token}` } });
    const data = await res.json();
    setPrescriptions(data);
  }

  async function add(e) {
    e.preventDefault();
    const meds = medications.split('\n').map(l => {
      const [name, dose, freq] = l.split('|').map(s => s?.trim());
      return { name, dose, frequency: freq };
    }).filter(m => m.name);

    await fetch('http://localhost:5000/api/prescriptions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
      body: JSON.stringify({ doctorName, medications: meds, notes })
    });
    setDoctorName(''); setMedications(''); setNotes('');
    fetchList();
  }

  return (
    <div>
      <h3>Add Prescription (for demo)</h3>
      <form onSubmit={add} style={{ maxWidth: 640 }}>
        <div className="form-row">
          <label>Doctor</label>
          <input value={doctorName} onChange={e=>setDoctorName(e.target.value)} />
        </div>
        <div className="form-row">
          <label>Medications (one per line, format: name | dose | frequency)</label>
          <textarea value={medications} onChange={e=>setMedications(e.target.value)} rows={4} />
        </div>
        <div className="form-row">
          <label>Notes</label>
          <input value={notes} onChange={e=>setNotes(e.target.value)} />
        </div>
        <div><button type="submit">Add Prescription</button></div>
      </form>

      <h3 style={{ marginTop: 16 }}>Prescriptions</h3>
      {prescriptions.map(p => (
        <div key={p._id} className="list-item">
          <strong>{p.doctorName}</strong> — {new Date(p.createdAt).toLocaleString()}
          <div>{p.notes}</div>
          <ul>
            {p.medications.map((m,i) => <li key={i}>{m.name} — {m.dose} — {m.frequency}</li>)}
          </ul>
        </div>
      ))}
    </div>
  );
}
